// Generates two test zip fixtures for manually exercising the bulk
// import flow. Both are tiny, pure-solid-color JPEGs generated by
// sharp — zero external asset dependencies.
//
// Run with:   node scripts/make-test-zip.mjs
//
// Output:
//   test-fixtures/sample-import.zip   (4 folders, 6 images)
//   test-fixtures/dup-test.zip        (1 image, identical bytes to
//                                      one image inside sample-import.zip
//                                      so it triggers duplicate detection)

import { mkdir, writeFile } from "node:fs/promises";
import path from "node:path";
import sharp from "sharp";
import AdmZip from "adm-zip";

const OUT_DIR = "test-fixtures";

// Deterministic so duplicate detection has something stable to match.
async function solidJpeg(r, g, b) {
  return sharp({
    create: {
      width: 640,
      height: 640,
      channels: 3,
      background: { r, g, b },
    },
  })
    .jpeg({ quality: 80, mozjpeg: false })
    .toBuffer();
}

const FILES = [
  { name: "nature/sunsets/golden-hour.jpg", rgb: [255, 180, 80] },
  { name: "nature/sunsets/amber-sky.jpg", rgb: [240, 140, 60] },
  { name: "nature/forests/deep-green.jpg", rgb: [30, 80, 40] },
  { name: "abstract/shapes/blue-field.jpg", rgb: [60, 110, 200] },
  { name: "abstract/shapes/purple-wave.jpg", rgb: [120, 80, 200] },
  { name: "space/nebula/cosmic-1.jpg", rgb: [80, 20, 120] },
];

async function main() {
  await mkdir(OUT_DIR, { recursive: true });

  // ── sample-import.zip ────────────────────────────────────
  const sample = new AdmZip();
  const buffers = {};
  for (const f of FILES) {
    const buf = await solidJpeg(...f.rgb);
    sample.addFile(f.name, buf);
    buffers[f.name] = buf;
  }
  const samplePath = path.join(OUT_DIR, "sample-import.zip");
  await writeFile(samplePath, sample.toBuffer());
  console.log(`✓ ${samplePath}  (${FILES.length} images, 4 folders)`);

  // ── dup-test.zip ────────────────────────────────────────
  // Re-packs one of the sample images under a different folder so
  // the sha256 matches an already-imported file byte-for-byte.
  const dup = new AdmZip();
  dup.addFile(
    "collections/retry/golden-hour-copy.jpg",
    buffers["nature/sunsets/golden-hour.jpg"],
  );
  dup.addFile(
    "collections/retry/new-image.jpg",
    await solidJpeg(200, 40, 40),
  );
  const dupPath = path.join(OUT_DIR, "dup-test.zip");
  await writeFile(dupPath, dup.toBuffer());
  console.log(`✓ ${dupPath}      (1 duplicate + 1 new)`);

  console.log("\nGroupings (FOLDER mode):");
  console.log("  sample-import.zip → 4 candidates:");
  console.log("    nature/sunsets   (2 assets)");
  console.log("    nature/forests   (1 asset)");
  console.log("    abstract/shapes  (2 assets)");
  console.log("    space/nebula     (1 asset)");
  console.log("  dup-test.zip → 1 candidate:");
  console.log("    collections/retry (2 assets, 1 flagged duplicate after");
  console.log("                       sample-import is approved)");
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});
